async (params, browser) => {
  // Open page
  await browser.open(`https://www.discogs.com/sell/release/${params.release_id}`)

  // Wait for content
  await browser.waitForSelector('table, [class*="Marketplace"], .mpitems', 15000)

  // Let page render
  await browser.wait(2500)

  // Scroll for more
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Extract data
  const page_data = await browser.evaluate(`const listings = Array.from(document.querySelectorAll('table tbody tr, [class*="MarketplaceItem"]')).slice(0,20).map(row => { const seller = row.querySelector('a[href*="/seller/"], .seller_info a')?.textContent?.trim()||''; const price = row.querySelector('.price, [class*="Price"]')?.textContent?.trim()||''; const cond = row.querySelector('.item_condition, [class*="Condition"]')?.textContent?.trim()?.replace(/\s+/g,' ')||''; const shipping = row.querySelector('.shipping_info, [class*="Shipping"]')?.textContent?.trim()||''; return { seller, price, condition: cond, shipping }; }).filter(l=>l.price); return { release_id: '' + params.release_id + '', listings, url: window.location.href }`)

  return page_data
}
